allowed_countries = [
    "United States", "Pakistan", "United Kingdom",
    "Australia", "Austrailia", "Netherland",
    "Netherlands", "India", "England"
]

allowed_sectors = [
    "Information Technology",
    "Software",
    "Automation",
    "Artificial Intelligence"
]


def get_nested(obj, path, default=None):
    current = obj
    for key in path:
        if isinstance(current, dict):
            current = current.get(key)
        else:
            return default

        if current is None:
            return default

    return current


def find_key(obj, target_key):
    if isinstance(obj, dict):
        for key, value in obj.items():
            if key == target_key:
                return value

            found = find_key(value, target_key)
            if found is not None:
                return found

    elif isinstance(obj, list):
        for item in obj:
            found = find_key(item, target_key)
            if found is not None:
                return found

    return None


